// HasProductionOrder applies the HasEdge predicate on the "production_order" edge.
func HasProductionOrder() predicate.ProductionOrderOperation {
	return predicate.ProductionOrderOperation(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ProductionOrderTable, ProductionOrderColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasProductionOrderWith applies the HasEdge predicate on the "production_order" edge with a given conditions (other predicates).
